// === CIRCUIT BREAKER ===
// Проверяем дневной PnL из статических данных воркфлоу
// Если убыток превышает $50 за день — останавливаем торги

const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);

// Сброс PnL при смене дня
if (staticData.pnlDate !== today) {
  staticData.pnlDate = today;
  staticData.dailyPnL = 0;
  staticData.tradesCount = 0;
}

const dailyPnL = staticData.dailyPnL || 0;
const tradesCount = staticData.tradesCount || 0;

if (dailyPnL < -50) {
  // Circuit breaker сработал — остановка торгов
  return [{
    json: {
      circuitBreaker: true,
      dailyPnL: dailyPnL,
      tradesCount: tradesCount,
      message: `ð CIRCUIT BREAKER: Дневной убыток $${Math.abs(dailyPnL).toFixed(2)} превысил лимит $50. Торги остановлены.`
    }
  }];
}

// Всё ОК — передаём дальше
return [{
  json: {
    circuitBreaker: false,
    dailyPnL: dailyPnL,
    tradesCount: tradesCount
  }
}];

// Разворачиваем массив пар в отдельные items для обработки в цикле
const pairs = JSON.parse($json.pairs);
return pairs.map(p => ({ json: p }));

// === MTF ANALYZER ===
// Мульти-таймфрейм анализ с RSI, EMA, MACD, ATR
// Score-based система генерации торговых сигналов

const symbol = $('Loop Over Pairs').item.json.symbol;

// Утилиты расчёта индикаторов
function parseCandles(raw) {
  if (!raw || !Array.isArray(raw)) return [];
  return raw.map(c => ({
    ts: parseInt(c[0]),
    o: parseFloat(c[1]),
    h: parseFloat(c[2]),
    l: parseFloat(c[3]),
    c: parseFloat(c[4]),
    v: parseFloat(c[5])
  })).sort((a, b) => a.ts - b.ts);
}

function calcRSI(closes, period = 14) {
  if (closes.length < period + 1) return 50;
  let gains = 0, losses = 0;
  for (let i = closes.length - period; i < closes.length; i++) {
    const diff = closes[i] - closes[i - 1];
    if (diff > 0) gains += diff;
    else losses += Math.abs(diff);
  }
  const avgGain = gains / period;
  const avgLoss = losses / period;
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - (100 / (1 + rs));
}

function calcEMA(closes, period) {
  if (closes.length < period) return closes[closes.length - 1];
  const k = 2 / (period + 1);
  let ema = closes.slice(0, period).reduce((a, b) => a + b) / period;
  for (let i = period; i < closes.length; i++) {
    ema = closes[i] * k + ema * (1 - k);
  }
  return ema;
}

function calcMACD(closes) {
  const ema12 = calcEMA(closes, 12);
  const ema26 = calcEMA(closes, 26);
  const macdLine = ema12 - ema26;
  // Сигнальная линия — EMA(9) от MACD (упрощённая)
  const signal = macdLine * 0.8; // Приближение
  const histogram = macdLine - signal;
  return { macdLine, signal, histogram };
}

function calcATR(candles, period = 14) {
  if (candles.length < period + 1) return 0;
  let trSum = 0;
  for (let i = candles.length - period; i < candles.length; i++) {
    const tr = Math.max(
      candles[i].h - candles[i].l,
      Math.abs(candles[i].h - candles[i - 1].c),
      Math.abs(candles[i].l - candles[i - 1].c)
    );
    trSum += tr;
  }
  return trSum / period;
}

// Парсим данные со всех трёх таймфреймов
const items = $input.all();
let raw15m = [], raw1h = [], raw4h = [];

try {
  // Данные приходят в разном формате — обрабатываем оба варианта
  const d0 = items[0]?.json?.data || items[0]?.json || [];
  const d1 = items[1]?.json?.data || items[1]?.json || [];
  const d2 = items[2]?.json?.data || items[2]?.json || [];
  raw15m = Array.isArray(d0) ? d0 : [];
  raw1h = Array.isArray(d1) ? d1 : [];
  raw4h = Array.isArray(d2) ? d2 : [];
} catch(e) {
  return [{ json: { signal: 'HOLD', reason: 'Ошибка парсинга данных: ' + e.message, symbol } }];
}

const candles15m = parseCandles(raw15m);
const candles1h = parseCandles(raw1h);
const candles4h = parseCandles(raw4h);

if (candles15m.length < 20 || candles1h.length < 20 || candles4h.length < 50) {
  return [{ json: { signal: 'HOLD', reason: 'Недостаточно данных для анализа', symbol } }];
}

// Текущая цена
const price = candles15m[candles15m.length - 1].c;

// RSI для каждого таймфрейма
const closes15m = candles15m.map(c => c.c);
const closes1h = candles1h.map(c => c.c);
const closes4h = candles4h.map(c => c.c);

const rsi15m = calcRSI(closes15m, 14);
const rsi1h = calcRSI(closes1h, 14);
const rsi4h = calcRSI(closes4h, 14);

// EMA(50) и EMA(200) для 4H
const ema50_4h = calcEMA(closes4h, 50);
const ema200_4h = calcEMA(closes4h, 200);

// MACD для 15M
const macd15m = calcMACD(closes15m);

// ATR(14) для 15M
const atr15m = calcATR(candles15m, 14);

// === SCORE-BASED LOGIC ===
let bullScore = 0;
let bearScore = 0;
let reasons = [];

// 4H тренд: цена выше EMA200 → бычий (+3)
if (price > ema200_4h) {
  bullScore += 3;
  reasons.push('4H: Цена > EMA200 (бычий тренд)');
} else {
  bearScore += 3;
  reasons.push('4H: Цена < EMA200 (медвежий тренд)');
}

// 4H: цена выше EMA50 → дополнительный бычий сигнал (+1)
if (price > ema50_4h) {
  bullScore += 1;
  reasons.push('4H: Цена > EMA50');
} else {
  bearScore += 1;
  reasons.push('4H: Цена < EMA50');
}

// 15M RSI перепроданность → BUY сигнал (+2)
if (rsi15m < 30) {
  bullScore += 2;
  reasons.push('15M: RSI < 30 (перепроданность)');
}

// 15M RSI перекупленность → SELL сигнал (+2)
if (rsi15m > 70) {
  bearScore += 2;
  reasons.push('15M: RSI > 70 (перекупленность)');
}

// 1H RSI > 65 → блокировка покупки
let buyBlocked = false;
if (rsi1h > 65) {
  buyBlocked = true;
  reasons.push('1H: RSI > 65 (BUY заблокирован)');
}

// MACD гистограмма положительная → бычий (+1)
if (macd15m.histogram > 0) {
  bullScore += 1;
  reasons.push('15M: MACD гистограмма > 0');
} else {
  bearScore += 1;
  reasons.push('15M: MACD гистограмма < 0');
}

// 4H RSI выше 60 → слабый бычий (+1)
if (rsi4h > 50 && rsi4h < 70) {
  bullScore += 1;
}
if (rsi4h < 40) {
  bearScore += 1;
}

// Определяем сигнал
let signal = 'HOLD';
let confidence = 0;
const maxScore = 8; // Максимально возможный балл

if (bullScore > bearScore && bullScore >= 4 && !buyBlocked) {
  signal = 'BUY';
  confidence = Math.min(Math.round((bullScore / maxScore) * 100), 95);
} else if (bearScore > bullScore && bearScore >= 4) {
  signal = 'SELL';
  confidence = Math.min(Math.round((bearScore / maxScore) * 100), 95);
} else {
  signal = 'HOLD';
  confidence = 0;
}

// Стоп-лосс и тейк-профит на основе ATR
const stopLoss = signal === 'BUY'
  ? parseFloat((price - atr15m * 2).toFixed(6))
  : parseFloat((price + atr15m * 2).toFixed(6));

const takeProfit = signal === 'BUY'
  ? parseFloat((price + atr15m * 4).toFixed(6))
  : parseFloat((price - atr15m * 4).toFixed(6));

return [{
  json: {
    symbol,
    signal,
    confidence,
    price,
    stopLoss,
    takeProfit,
    atr: parseFloat(atr15m.toFixed(6)),
    rsi15m: parseFloat(rsi15m.toFixed(2)),
    rsi1h: parseFloat(rsi1h.toFixed(2)),
    rsi4h: parseFloat(rsi4h.toFixed(2)),
    ema50_4h: parseFloat(ema50_4h.toFixed(6)),
    ema200_4h: parseFloat(ema200_4h.toFixed(6)),
    macdHistogram: parseFloat(macd15m.histogram.toFixed(6)),
    bullScore,
    bearScore,
    buyBlocked,
    reasons,
    timestamp: new Date().toISOString()
  }
}];

// === ПРОВЕРКА ОТКРЫТЫХ ПОЗИЦИЙ ===
// Bitget v2 API: получить открытые ордера
// Используем HMAC-SHA256 для подписи

const crypto = require('crypto');

const apiKey = $env.BITGET_API_KEY;
const secretKey = $env.BITGET_SECRET_KEY;
const passphrase = $env.BITGET_PASSPHRASE;

const timestamp = Date.now().toString();
const method = 'GET';
const requestPath = '/api/v2/spot/trade/unfilled-orders';
const queryString = '?startTime=' + (Date.now() - 86400000);
const body = '';

// Формируем строку для подписи
const prehash = timestamp + method + requestPath + queryString + body;
const signature = crypto.createHmac('sha256', secretKey)
  .update(prehash)
  .digest('base64');

// Делаем запрос
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.bitget.com' + requestPath + queryString,
  headers: {
    'ACCESS-KEY': apiKey,
    'ACCESS-SIGN': signature,
    'ACCESS-TIMESTAMP': timestamp,
    'ACCESS-PASSPHRASE': passphrase,
    'Content-Type': 'application/json',
    'locale': 'en-US'
  }
});

const orders = response.data || [];
const openCount = Array.isArray(orders) ? orders.length : 0;

return [{
  json: {
    ...$input.first().json,
    openPositions: openCount,
    canTrade: openCount < 3
  }
}];

// === PLACE ORDER ===
// Размещение рыночного ордера через Bitget Spot API v2
// HMAC-SHA256 подпись согласно документации Bitget

const crypto = require('crypto');

const apiKey = $env.BITGET_API_KEY;
const secretKey = $env.BITGET_SECRET_KEY;
const passphrase = $env.BITGET_PASSPHRASE;

const data = $json;
const side = data.signal === 'BUY' ? 'buy' : 'sell';

const timestamp = Date.now().toString();
const method = 'POST';
const requestPath = '/api/v2/spot/trade/place-order';

const bodyObj = {
  symbol: data.symbol,
  side: side,
  orderType: 'market',
  size: '50',
  force: 'gtc'
};

const bodyStr = JSON.stringify(bodyObj);

// HMAC-SHA256 подпись
const prehash = timestamp + method + requestPath + bodyStr;
const signature = crypto.createHmac('sha256', secretKey)
  .update(prehash)
  .digest('base64');

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.bitget.com' + requestPath,
    headers: {
      'ACCESS-KEY': apiKey,
      'ACCESS-SIGN': signature,
      'ACCESS-TIMESTAMP': timestamp,
      'ACCESS-PASSPHRASE': passphrase,
      'Content-Type': 'application/json',
      'locale': 'en-US'
    },
    body: bodyObj
  });

  return [{
    json: {
      ...data,
      orderId: response.data?.orderId || 'unknown',
      orderStatus: 'placed',
      side: side,
      orderSize: 50
    }
  }];
} catch (err) {
  return [{
    json: {
      ...data,
      orderId: null,
      orderStatus: 'failed',
      orderError: err.message,
      side: side
    }
  }];
}

// === SET STOP LOSS ===
// Устанавливаем план-ордер (стоп-лосс) через Bitget API
// triggerPrice берём из MTF Analyzer расчёта

const crypto = require('crypto');

const apiKey = $env.BITGET_API_KEY;
const secretKey = $env.BITGET_SECRET_KEY;
const passphrase = $env.BITGET_PASSPHRASE;

const data = $json;

if (!data.orderId || data.orderStatus === 'failed') {
  return [{ json: { ...data, stopLossStatus: 'skipped', reason: 'Ордер не был размещён' } }];
}

const timestamp = Date.now().toString();
const method = 'POST';
const requestPath = '/api/v2/spot/trade/place-plan-order';

const side = data.signal === 'BUY' ? 'sell' : 'buy'; // Стоп-лосс = обратная сторона

const bodyObj = {
  symbol: data.symbol,
  side: side,
  triggerPrice: data.stopLoss.toString(),
  orderType: 'market',
  size: data.orderSize.toString(),
  triggerType: 'mark_price',
  planType: 'normal_plan'
};

const bodyStr = JSON.stringify(bodyObj);
const prehash = timestamp + method + requestPath + bodyStr;
const signature = crypto.createHmac('sha256', secretKey)
  .update(prehash)
  .digest('base64');

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.bitget.com' + requestPath,
    headers: {
      'ACCESS-KEY': apiKey,
      'ACCESS-SIGN': signature,
      'ACCESS-TIMESTAMP': timestamp,
      'ACCESS-PASSPHRASE': passphrase,
      'Content-Type': 'application/json',
      'locale': 'en-US'
    },
    body: bodyObj
  });

  return [{
    json: {
      ...data,
      stopLossOrderId: response.data?.orderId || 'unknown',
      stopLossStatus: 'placed'
    }
  }];
} catch (err) {
  return [{
    json: {
      ...data,
      stopLossOrderId: null,
      stopLossStatus: 'failed',
      stopLossError: err.message
    }
  }];
}

// === ЛОГИРОВАНИЕ СДЕЛКИ ===
// Обновляем PnL в статических данных воркфлоу
// и формируем запись для Google Sheets

const staticData = $getWorkflowStaticData('global');
staticData.tradesCount = (staticData.tradesCount || 0) + 1;

const data = $json;

return [{
  json: {
    timestamp: data.timestamp,
    symbol: data.symbol,
    signal: data.signal,
    price: data.price,
    stopLoss: data.stopLoss,
    takeProfit: data.takeProfit,
    confidence: data.confidence + '%',
    rsi15m: data.rsi15m,
    rsi1h: data.rsi1h,
    rsi4h: data.rsi4h,
    orderId: data.orderId || 'N/A',
    orderStatus: data.orderStatus,
    stopLossStatus: data.stopLossStatus || 'N/A',
    bullScore: data.bullScore,
    bearScore: data.bearScore
  }
}];
